// Generated by zk-gate/circuits/prove.js — a real snarkjs proof that verified
// as true against verification_key.json. Proves vk.rs + the verifier agree.
#[test]
fn verifies_known_good_proof_from_snarkjs() {
    use ark_ff::MontFp;
    let proof = Proof {
        a: G1Affine::new_unchecked(MontFp!("4239522745028957489128814424898175527480065585604935930325194557893242018355"), MontFp!("16987997168109485916849467680733306036942399903431014517509530321491933625334")),
        b: G2Affine::new_unchecked(
            Fq2::new(MontFp!("366568643644030338372018074053157508914731409953289259159399768731836114667"), MontFp!("20903976515138242262287480514054783977726890705219798529857958630333117228653")),
            Fq2::new(MontFp!("17651726827595585702305325802963151406084507059743241361705509739574981957005"), MontFp!("15334379907997893142056614185605892240242907275594488722412550680285948008262")),
        ),
        c: G1Affine::new_unchecked(MontFp!("9206677908401175626371876379420723207625882141507208621085942334567260137308"), MontFp!("4452617138188918891108912525986360782079527174316811344216607658818890651941")),
    };
    let public_inputs: Vec<Fr> = vec![
        MontFp!("16331994690242190256441629756923135657650690078906869969179988007525570044228"), // root
        MontFp!("3802738485917981484706746213243764881401701150297038837377548566657572751513"), // nullifierHash
        MontFp!("8798115572335137181385764574899340864321227978644487913055311860416701407699"), // account
    ];
    let vk = get_verification_key();
    let pvk = prepare_verifying_key(&vk);
    assert!(
        Groth16::<Bn254>::verify_with_processed_vk(&pvk, &public_inputs, &proof).unwrap_or(false),
        "Rust verifier rejected a proof snarkjs verified as true"
    );
}
